// // This module performs a division operation on two 2-bit numbers. It calculates the quotient and remainder of the division. If the denominator is zero, it sets both the quotient and remainder to zero.
module divider_2bit(
    input [1:0] numerator,
    input [1:0] denominator,
    output reg [1:0] quotient,
    output reg [1:0] remainder
);
    always @(*) begin
        if (denominator == 2'b00) begin
            quotient = 2'b00;
            remainder = 2'b00;
        end else begin
            quotient = numerator / denominator;
            remainder = numerator % denominator;
        end
    end
endmodule
